package assignment04PartD;public class CircularDoublyLinkedDeque<T> implements DequeInterface<T> {    DoublyLinkedNode tail;    int length;    public CircularDoublyLinkedDeque(){        tail = null;        length = 0;    }    @Override    public T getFront() {        return tail.nextNode.data;    }    @Override    public T getBack() {        return tail.data;    }    @Override    public void addToFront(T newEntry) {        DoublyLinkedNode temp = new DoublyLinkedNode(newEntry);        if (tail == null){            tail = temp;            tail.nextNode = tail;        } else {            temp.nextNode = tail.nextNode;            tail.nextNode = temp;        }        length++;    }    @Override    public void addToBack(T newEntry) {        addToFront(newEntry);        tail = tail.nextNode;    }    @Override    public boolean isEmpty() {        return tail == null;    }    @Override    public T removeFront() {        if(isEmpty()){            throw new EmptyQueueException();        }        DoublyLinkedNode temp = tail.nextNode;        if ( tail == tail.nextNode ){            tail = null;        } else{            tail.nextNode = temp.nextNode;            temp.nextNode = null;        }        length--;        return temp.data;    }    @Override    public T removeBack() {        if(isEmpty()){            throw new EmptyQueueException();        }        DoublyLinkedNode current = tail;        while ( current.nextNode != tail ){            current = current.nextNode;        }        DoublyLinkedNode temp = tail;        if ( current == tail ){            tail = tail;        } else {            current.nextNode = tail.nextNode;            tail = current;        }        length--;        return temp.data;    }    @Override    public void clear() {        tail = null;    }    private class DoublyLinkedNode {        private DoublyLinkedNode nextNode;        private T data;        private DoublyLinkedNode(T data){            this(data,null);        }        private DoublyLinkedNode(T data, DoublyLinkedNode nextNode){            this.data = data;            this.nextNode = nextNode;        }    }}